#include<cstdio>
#include<algorithm>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmax(T&x,const T&w){x<w?x=w:T();}
template<typename T> inline void chkmin(T&x,const T&w){w<x?x=w:T();}
const int N=1e6+10,INF=0x3f3f3f3f;int T[N],P[N],Px[N],Py[N],px,py,x[N],y[N],ans[N],n,V[N],sx[N],sy[N];bool opt[N];
inline int bndx(const int &k){int l(1),r(px),m;while(l<=r)Px[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline int bndy(const int &k){int l(1),r(py),m;while(l<=r)Py[m=(l+r)>>1]<=k?l=m+1:r=m-1;return l-1;}
inline bool cmpx(const int &a,const int &b){return x[a]==x[b]?y[a]<y[b]:x[a]<x[b];}
inline void ins(int p,const int &x){while(p<=py)chkmax(T[p],x),p+=(p&-p);}
inline int qry(int p){int res(-INF);while(p)chkmax(res,T[p]),p^=(p&-p);return res;}
inline void del(int p){while(p<=py)T[p]=-INF,p+=(p&-p);}
inline void cdq(const int &l,const int &r)
{
	if(l==r)return;int mid=(l+r)>>1;cdq(l,mid);cdq(mid+1,r);
	std::sort(P+l,P+mid+1,cmpx); std:: sort(P+mid+1,P+r+1,cmpx);
//	printf("[%d,%d] :: \n",l,r);
//	rep(l,r,i)printf("%d :: (%d,%d,%d) %d\n",i,P[i],x[P[i]],y[P[i]],opt[P[i]]);
	int pl=l;rep(mid+1,r,pr)if(opt[P[pr]])
	{
		while(pl<=mid&&x[P[pl]]<=x[P[pr]]){if(!opt[P[pl]])ins(y[P[pl]],V[P[pl]]);++pl;}
		chkmin(ans[P[pr]],V[P[pr]]-qry(y[P[pr]]));
	}
	for(int i=l;i<pl;++i)del(y[P[i]]);
//	rep(1,n,i)printf("%d ",ans[i]==INF?-9:ans[i]);puts("");
}
int main()
{
//	FIN("data.in");FOUT("mine.out");
	memset(T,~0x3f,sizeof(T));memset(ans,0x3f,sizeof(ans));
	n=read();int m=read();rep(1,n,i)Px[i]=x[i]=sx[i]=read(),Py[i]=y[i]=sy[i]=read();
	n+=m;rep(n-m+1,n,i){opt[i]=read()-1;Px[i]=x[i]=sx[i]=read();Py[i]=y[i]=sy[i]=read();}
	std::sort(Px+1,Px+n+1);px=std::unique(Px+1,Px+n+1)-Px-1;
	std::sort(Py+1,Py+n+1);py=std::unique(Py+1,Py+n+1)-Py-1;
	rep(1,n,i)x[i]=bndx(x[i]),y[i]=bndy(y[i]),V[P[i]=i]=sx[i]+sy[i];
//	printf("px=%d ; py=%d;\n",px,py);
//	rep(1,n,i)printf("%d :: %d %d %d\n",i,x[i],y[i],opt[i]);
	cdq(1,n);
	rep(1,n,i)x[i]=px-x[i]+1,V[P[i]=i]=-sx[i]+sy[i];cdq(1,n);
	rep(1,n,i)y[i]=py-y[i]+1,V[P[i]=i]=-sx[i]-sy[i];cdq(1,n);
	rep(1,n,i)x[i]=px-x[i]+1,V[P[i]=i]=+sx[i]-sy[i];cdq(1,n);
	rep(1,n,i)if(opt[i])printf("%d\n",ans[i]);return 0;
}
